const body = $input.first().json.body;

const fecha = new Date(body.fecha).toLocaleDateString('es-ES', {
  day: 'numeric', month: 'long', year: 'numeric'
});

const html = `
<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; padding: 40px; color: #2d3a1f; }
    h1 { color: #4a7c59; font-size: 28px; margin-bottom: 4px; }
    .subtitle { color: #7a8c6a; font-size: 14px; margin-bottom: 32px; }
    .section { background: #f5f0e8; border-radius: 12px; padding: 20px; margin-bottom: 20px; }
    .section h2 { font-size: 16px; color: #4a7c59; margin: 0 0 12px; }
    .section p { margin: 0; font-size: 14px; line-height: 1.6; }
    .kcal { font-size: 32px; font-weight: bold; color: #4a7c59; }
    .footer { margin-top: 40px; font-size: 12px; color: #999; text-align: center; }
  </style>
</head>
<body>
  <h1>🐾 Plan Nutricional Kahu</h1>
  <div class="subtitle">Generado el ${fecha} · ${body.mascota_nombre || 'Tu mascota'}</div>

  <div class="section">
    <h2>Calorías totales</h2>
    <span class="kcal">${Math.round(body.calorias_total)} kcal</span>
  </div>

  <div class="section">
    <h2>Ingredientes</h2>
    <p>${body.ingredientes}</p>
  </div>

  <div class="section">
    <h2>Proporciones</h2>
    <p>${body.proporciones}</p>
  </div>

  ${body.notas_ia ? `
  <div class="section">
    <h2>Notas del asistente IA</h2>
    <p>${body.notas_ia}</p>
  </div>` : ''}

  <div class="footer">Generado por Kahu · kahuappcontact@gmail.com</div>
</body>
</html>
`;

return [{ json: { html, body } }];
